import{_ as a,c as i,o as t,a5 as o}from"./chunks/framework.GGEQ5PbI.js";const u=JSON.parse('{"title":"Frequently Asked Questions (FAQ)","description":"","frontmatter":{},"headers":[],"relativePath":"docs/about-faq.md","filePath":"docs/about-faq.md","lastUpdated":1768442972000}'),n={name:"docs/about-faq.md"};function s(r,e,d,c,l,h){return t(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="frequently-asked-questions-faq" tabindex="-1">Frequently Asked Questions (FAQ) <a class="header-anchor" href="#frequently-asked-questions-faq" aria-label="Permalink to “Frequently Asked Questions (FAQ)”">​</a></h1><h2 id="q-why-does-continuous-input-of-xy-appear-in-upright-font-instead-of-italic" tabindex="-1">Q: Why does continuous input of <code>xy</code> appear in upright font instead of italic? <a class="header-anchor" href="#q-why-does-continuous-input-of-xy-appear-in-upright-font-instead-of-italic" aria-label="Permalink to “Q: Why does continuous input of xy appear in upright font instead of italic?”">​</a></h2><p>A: In Liii STEM, continuous input of <code>xy</code> is interpreted as an operator, therefore it appears in upright font (this behavior is equivalent to <code>\\mathrm{xy}</code> in LaTeX). If your actual meaning is <code>x</code> multiplied by <code>y</code>, you can add an extra space between <code>xy</code> (a stricter approach is to input a space followed by <code>Tab</code>, which inputs an invisible multiplication symbol).</p><h2 id="q-how-to-input-subscript-for-lim" tabindex="-1">Q: How to input subscript for <code>lim</code> <a class="header-anchor" href="#q-how-to-input-subscript-for-lim" aria-label="Permalink to “Q: How to input subscript for lim”">​</a></h2><p>A: Enter Math Mode and input <code>lim</code>, then input <code>_</code> to add content below the limit <code>lim</code>. Video tutorial: <a href="https://www.bilibili.com/video/BV1UryaBSEfu/?share_source=copy_web&amp;vd_source=eda0e38770802e507d57d1ac0d3b5b57" target="_blank" rel="noreferrer">Liii STEM: How to Input Limits</a></p><h2 id="q-how-to-adjust-the-display-style-of-mathematical-formulas" tabindex="-1">Q: How to adjust the display style of mathematical formulas <a class="header-anchor" href="#q-how-to-adjust-the-display-style-of-mathematical-formulas" aria-label="Permalink to “Q: How to adjust the display style of mathematical formulas”">​</a></h2><p>A: The display style for inline formulas is enabled by default, while for displayed formulas it is disabled by default. You can select the formula and adjust it through the Toolbar: <code>Format</code> → <code>Display style</code>.</p><h2 id="q-can-invoices-be-issued" tabindex="-1">Q: Can invoices be issued? <a class="header-anchor" href="#q-can-invoices-be-issued" aria-label="Permalink to “Q: Can invoices be issued?”">​</a></h2><p>A: Yes, after payment, please contact customer service and provide invoice header information. We will have dedicated personnel issue the invoice for you.</p><h2 id="q-why-am-i-not-receiving-email-verification-codes" tabindex="-1">Q: Why am I not receiving email verification codes? <a class="header-anchor" href="#q-why-am-i-not-receiving-email-verification-codes" aria-label="Permalink to “Q: Why am I not receiving email verification codes?”">​</a></h2><p>A: If you haven&#39;t received the email verification code for a long time, please check your spam folder first. Using foreign email addresses may result in not receiving verification codes (such as Gmail).</p><h2 id="q-what-is-the-relationship-between-texmacs-mogan-stem-and-liii-stem" tabindex="-1">Q: What is the relationship between TeXmacs, Mogan STEM, and Liii STEM? <a class="header-anchor" href="#q-what-is-the-relationship-between-texmacs-mogan-stem-and-liii-stem" aria-label="Permalink to “Q: What is the relationship between TeXmacs, Mogan STEM, and Liii STEM?”">​</a></h2><p>A: Mogan STEM (Community Edition) is developed based on TeXmacs 2.1.4. Liii STEM (Commercial Edition) adds built-in AI and formula recognition features on top of Mogan STEM.</p><h2 id="q-can-commutative-diagrams-be-drawn" tabindex="-1">Q: Can commutative diagrams be drawn? <a class="header-anchor" href="#q-can-commutative-diagrams-be-drawn" aria-label="Permalink to “Q: Can commutative diagrams be drawn?”">​</a></h2><p>A: Yes, enter Math Mode and use the Toolbar: <code>Insert</code> → <code>Image</code> → <code>Commutative diagram</code> to draw commutative diagrams. Video tutorial: <a href="https://www.bilibili.com/video/BV1AJvYBpEmv?share_source=copy_web&amp;vd_source=eda0e38770802e507d57d1ac0d3b5b57&amp;spm_id_from=333.788.videopod.sections" target="_blank" rel="noreferrer">Liii STEM: The World&#39;s Fastest Method for Drawing Commutative Diagrams</a></p>',15)])])}const p=a(n,[["render",s]]);export{u as __pageData,p as default};
